sys_ui_policy.script_true:
function onCondition() {
	// STRY0085538
	var state = g_scratchpad.currentState;
	var inReview = (state == "14");
	var isTaskOwner = g_user.userID == g_form.getValue('u_task_requester');
	var isReviewer = g_user.userID == g_form.getValue('u_reviewer');
	var showAssignedMember = (g_form.getDisplayValue("provide_response") == 'false') 
							&& g_user.userID == g_form.getValue('assigned_to');

	var review_commentsPopulated = (g_form.getValue("comments_dt")+'' != '');

	// if in review state, always show the rework comments, if not in review state, only show value IF populated
	if(inReview && (isTaskOwner || isReviewer || showAssignedMember))
		g_form.setDisplay('comments_dt', true);
	else
		g_form.setDisplay('comments_dt', review_commentsPopulated);
}
